.zo-game-root--microbe-rts{max-width:900px;margin:0 auto;padding:18px;border-radius:24px;background:linear-gradient(180deg,#f2fff8,#bde7d4);color:#173329;font-family:"Trebuchet MS","Segoe UI",sans-serif}.zo-game-root--microbe-rts *{box-sizing:border-box}.mr-top{display:grid;grid-template-columns:repeat(5,1fr);gap:10px;margin-bottom:14px}.mr-stat,.mr-panel{background:rgba(255,255,255,.62);border:1px solid rgba(23,51,41,.12);border-radius:16px;padding:12px}.mr-stat strong{display:block;font-size:12px;text-transform:uppercase;color:#527362}.mr-board{display:grid;grid-template-columns:repeat(6,1fr);gap:8px;background:#77b99d;padding:12px;border-radius:18px}.mr-cell{aspect-ratio:1;border-radius:12px;background:#e8fff2;display:flex;align-items:center;justify-content:center;font-size:22px;cursor:pointer}.mr-btns{display:flex;flex-wrap:wrap;gap:8px;margin:12px 0}.mr-btn{border:0;border-radius:12px;padding:10px 14px;background:#2f8c61;color:#fff;font-weight:700;cursor:pointer}
