$js=<<<'JS'
document.addEventListener('DOMContentLoaded',function(){document.querySelectorAll('.zo-game-root--microbe-rts').forEach(function(root){const boardEl=root.querySelector('[data-board]'),massEl=root.querySelector('[data-mass]'),mutEl=root.querySelector('[data-mutation]'),immuneEl=root.querySelector('[data-immune]'),goalEl=root.querySelector('[data-goal]'),turnEl=root.querySelector('[data-turn]'),logEl=root.querySelector('[data-log]');let s;function key(x,y){return x+','+y}function reset(){s={owned:new Set(['0,2','0,3']),enemy:new Set(['5,1','5,4']),mass:2,mutation:0,turn:1,selected:null,log:'Expand across the body. Mutation helps you survive immune attacks.'};render()}function clickCell(x,y){const k=key(x,y);if(s.owned.has(k)){s.selected=k;s.log='Cell colony selected. Expand into a neighboring tile.'}else if(s.selected){const p=s.selected.split(',');if(Math.abs(Number(p[0])-x)+Math.abs(Number(p[1])-y)===1&&!s.enemy.has(k)){s.owned.add(k);s.mass++;s.log='Colony expanded. New tissue claimed.';immuneTurn();s.selected=null}}render()}function mutate(){if(s.mass<2)return;s.mass-=2;s.mutation++;s.log='Mutation purchased. Your cells resist the next immune sweep.';render()}function immuneTurn(){s.turn++;const targets=[...s.owned].filter(function(k){const p=k.split(',');return Number(p[0])>2});if(targets.length){const hit=targets[Math.floor(Math.random()*targets.length)];if(s.mutation>0){s.mutation--;s.log='Immune attack blocked by mutation.'}else{s.owned.delete(hit);s.mass=Math.max(1,s.mass-1);s.log='Immune cells destroyed one outer colony.'}}if(s.owned.size>=12)s.log='Body sector dominated. Your microbe swarm survived and spread.'}function render(){boardEl.innerHTML='';for(let y=0;y<6;y++){for(let x=0;x<6;x++){const k=key(x,y),c=document.createElement('button');c.type='button';c.className='mr-cell';if(s.enemy.has(k))c.textContent='🛡';if(s.owned.has(k))c.textContent=s.selected===k?'🧫':'🦠';c.addEventListener('click',function(){clickCell(x,y)});boardEl.appendChild(c)}}massEl.textContent=String(s.mass);mutEl.textContent=String(s.mutation);immuneEl.textContent=s.mutation>0?'Resistant':'Fragile';goalEl.textContent=s.owned.size+'/12';turnEl.textContent=String(s.turn);logEl.textContent=s.log}root.querySelector('[data-mutate]').addEventListener('click',mutate);root.querySelector('[data-restart]').addEventListener('click',reset);reset()})});
JS;
if(!function_exists('zo_game_microbe_rts_render')){function zo_game_microbe_rts_render($post_id=0,$module=array()){ob_start();?>
<div class="zo-game-root zo-game-root--microbe-rts">
